import React from "react";
import styles from "./payment-form.module.css";
import Stepper from "../stepper";
import SummaryInfo from "../summary-info";
import PaymentMethod from "./payment-method";
import TaxInfo from "./tax-info";
import BillingAddress from "./billing-address";
import CheckoutButtons from "../checkout-buttons";
import { useTranslation } from "react-i18next";

const PaymentForm = () => {
  const [t] = useTranslation("global");

  return (
    <div className={styles.payment__form}>
      <Stepper active="Payment" passed={["Cart", "Details", "Shipping"]} />
      <SummaryInfo
        showContact={true}
        showAddress={true}
        showShippingMethod={true}
      />
      <PaymentMethod />
      <TaxInfo />
      <BillingAddress />
      <CheckoutButtons
        btnBack_text="shipping"
        btnBack_to="/checkout/shipping"
        btnNext_text="Pay now"
        btnNext_to="/checkout/confirmation"
      />
    </div>
  );
};

export default PaymentForm;
